const TZ = "America/Mexico_City";

function pad2(n) {
  return String(n).padStart(2, "0");
}

function todayIsoInTz(tz) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(new Date());
  const y = parts.find((p) => p.type === "year")?.value;
  const m = parts.find((p) => p.type === "month")?.value;
  const d = parts.find((p) => p.type === "day")?.value;
  return y && m && d ? y + "-" + m + "-" + d : "";
}

function isoToDMY(iso) {
  const s = String(iso || "").trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return "";
  const p = s.split("-");
  return p[2] + "/" + p[1] + "/" + p[0]; // DD/MM/YYYY
}

function isoFromYMD(y, m, d) {
  const yy = Number(y);
  const mm = Number(m);
  const dd = Number(d);
  if (!Number.isFinite(yy) || !Number.isFinite(mm) || !Number.isFinite(dd)) return "";
  if (mm < 1 || mm > 12 || dd < 1 || dd > 31) return "";
  const dt = new Date(Date.UTC(yy, mm - 1, dd));
  if (dt.getUTCFullYear() !== yy || dt.getUTCMonth() !== (mm - 1) || dt.getUTCDate() !== dd) return "";
  return String(yy) + "-" + pad2(mm) + "-" + pad2(dd);
}

function excelSerialToIso(serial) {
  const num = Number(serial);
  if (!Number.isFinite(num) || num < 1000) return "";
  const utcDays = Math.floor(num - 25569);
  const date = new Date(utcDays * 86400 * 1000);
  return String(date.getUTCFullYear()) + "-" + pad2(date.getUTCMonth() + 1) + "-" + pad2(date.getUTCDate());
}
// Parsea cualquier fecha cruda a ISO. Para fechas p1/p2/YYYY ambiguas,
// intenta DD/MM primero (locale MX). Retorna "" si no puede.
function parseAnyDateToIso(raw) {
  const s = String(raw || "").trim();
  if (!s || s === "00-00-00") return "";

  // Ya es ISO
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;

  // Formato p1/p2/YYYY o p1-p2-YYYY
  const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
  if (m) {
    let p1 = Number(m[1]), p2 = Number(m[2]), yy = Number(m[3]);
    if (yy < 100) yy = yy >= 70 ? 1900 + yy : 2000 + yy;
    if (p1 > 12) {
      // p1 es día �?' DD/MM/YYYY
      return isoFromYMD(yy, p2, p1);
    } else if (p2 > 12) {
      // p2 es día �?' MM/DD/YYYY
      return isoFromYMD(yy, p1, p2);
    } else {
      // Ambigua: asumir DD/MM (MX) como mejor guess
      return isoFromYMD(yy, p2, p1);
    }
  }

  // Serial de Excel
  const asNum = Number(s);
  if (Number.isFinite(asNum) && asNum > 1000) {
    return excelSerialToIso(asNum);
  }

  return "";
}

// Calcula fecha venc = base + plazo días
// base = K si K válida, sino J
function calcularDesdeBase(rawK, rawJ, plazo) {
  const sK = String(rawK || "").trim();
  const kValida = sK !== "" && sK !== "00-00-00" && sK !== "0";
  const baseRaw = kValida ? rawK : rawJ;
  const baseIso = parseAnyDateToIso(baseRaw);
  if (!baseIso) return "";

  const days = parseInt(String(plazo || "0"), 10) || 0;
  const d = new Date(baseIso + "T00:00:00Z");
  d.setUTCDate(d.getUTCDate() + days);
  return String(d.getUTCFullYear()) + "-" + pad2(d.getUTCMonth() + 1) + "-" + pad2(d.getUTCDate());
}

// Resuelve la fecha de vencimiento usando el algoritmo:
// M no ambigua �?' usar M directamente
// M ambigua   �?' (K válida ? K : J) + L días
function resolveVencimientoIso(rawM, rawK, rawJ, plazo) {
  const sM = String(rawM || "").trim();

  // Caso 1: M es formato p1/p2/YYYY
  const slash = sM.match(/^(\d{1,2})[\/](\d{1,2})[\/](\d{2,4})$/);
  if (slash) {
    const p1 = Number(slash[1]);
    const p2 = Number(slash[2]);

    if (p1 > 12 || p2 > 12) {
      // NO AMBIGUA: podemos determinar día y mes
      let yy = Number(slash[3]);
      if (yy < 100) yy = yy >= 70 ? 1900 + yy : 2000 + yy;
      if (p1 > 12) {
        return isoFromYMD(yy, p2, p1); // DD/MM/YYYY
      } else {
        return isoFromYMD(yy, p1, p2); // MM/DD/YYYY
      }
    }

    // AMBIGUA: p1 <= 12 y p2 <= 12 �?' calcular desde base + plazo
    return calcularDesdeBase(rawK, rawJ, plazo);
  }

  // Caso 2: M es ISO directo (raro pero posible)
  if (/^\d{4}-\d{2}-\d{2}$/.test(sM)) return sM;

  // Caso 3: M es serial de Excel u otro �?' AMBIGUA
  return calcularDesdeBase(rawK, rawJ, plazo);
}


function parseSlashParts(str) {
  const m = String(str || "").trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/);
  if (!m) return null;
  let a = Number(m[1]);
  let b = Number(m[2]);
  let y = Number(m[3]);
  if (!Number.isFinite(a) || !Number.isFinite(b) || !Number.isFinite(y)) return null;
  if (y < 100) y = y >= 70 ? 1900 + y : 2000 + y;
  return { a, b, y };
}



function daysBetween(aIso, bIso) {
  const a = new Date(aIso + "T00:00:00Z");
  const b = new Date(bIso + "T00:00:00Z");
  return Math.round((b.getTime() - a.getTime()) / 86400000);
}





